// Generated by OrchestKit Claude Plugin
// Created: 2026-04-17

/**
 * Subagent Scope Auditor — SubagentStop hook
 *
 * Source: usage analytics #5 friction point — sub-agents modify files
 * outside their declared scope in 3+ sessions (out of 481 Agent calls
 * across 126 sessions). Existing `subagent-validator` validates agent
 * CONFIGURATION at spawn time; this hook validates FILE ACCESS at
 * completion.
 *
 * Approach: parse the agent's transcript (provided via
 * `agent_transcript_path`, CC 2.1.69+), extract every Write/Edit/MultiEdit
 * tool call, compare the edited paths against the agent's declared
 * scope (derived from the spawn prompt + task description), and flag
 * out-of-scope modifications.
 *
 * Advisory only. The context injection tells the parent session which
 * files were touched outside scope — it does NOT revert or block the
 * changes. Reverting is a human decision.
 */

import { existsSync, readFileSync } from 'node:fs';
import { basename } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'subagent-stop/subagent-scope-auditor';

const MAX_OUT_OF_SCOPE_LINES = 8;

// Transcript line shape (JSONL — one JSON object per line)
interface TranscriptLine {
  type?: string;
  tool_use?: { name?: string; input?: { file_path?: string } };
  message?: { content?: unknown };
  // Spawn prompt lives on the first user-message line; we sniff the content.
}

/**
 * Read the agent transcript and return the list of files the agent wrote
 * to (via Write/Edit/MultiEdit). Deduplicated, ordered by first appearance.
 */
function extractEditedFiles(transcriptPath: string): string[] {
  if (!existsSync(transcriptPath)) return [];
  let content: string;
  try {
    content = readFileSync(transcriptPath, 'utf8');
  } catch {
    return [];
  }
  const seen = new Set<string>();
  const ordered: string[] = [];
  for (const raw of content.split('\n')) {
    if (!raw.trim()) continue;
    let parsed: TranscriptLine;
    try {
      parsed = JSON.parse(raw);
    } catch {
      continue;
    }
    const toolName = parsed.tool_use?.name;
    const filePath = parsed.tool_use?.input?.file_path;
    if (!toolName || !filePath) continue;
    if (!['Write', 'Edit', 'MultiEdit'].includes(toolName)) continue;
    if (!seen.has(filePath)) {
      seen.add(filePath);
      ordered.push(filePath);
    }
  }
  return ordered;
}

/**
 * Pull the spawn prompt from the transcript's first user-message entry.
 * Returns an empty string on any failure.
 */
function readSpawnPrompt(transcriptPath: string): string {
  if (!existsSync(transcriptPath)) return '';
  try {
    const content = readFileSync(transcriptPath, 'utf8');
    for (const raw of content.split('\n')) {
      if (!raw.trim()) continue;
      const parsed = JSON.parse(raw) as TranscriptLine;
      if (parsed.type === 'user' && typeof parsed.message?.content === 'string') {
        return parsed.message.content;
      }
      if (parsed.type === 'user' && Array.isArray(parsed.message?.content)) {
        const texts = parsed.message.content
          .map(c => (c as { text?: string }).text)
          .filter(Boolean);
        if (texts.length > 0) return texts.join('\n');
      }
    }
  } catch {
    // fall through
  }
  return '';
}

/**
 * Heuristic scope extraction: pull filenames, path fragments, and
 * directory names that the spawn prompt mentions explicitly. Files the
 * agent edits that share NONE of these fragments are flagged.
 */
function extractScopeFragments(prompt: string): Set<string> {
  const fragments = new Set<string>();
  if (!prompt) return fragments;

  // File paths with an extension — strong signal
  const pathRe = /[\w./-]+\.(ts|tsx|js|jsx|py|md|json|yaml|yml|sh|mjs|cjs|go|rs|java|rb)/g;
  const paths = prompt.match(pathRe) || [];
  for (const p of paths) fragments.add(p);

  // Bare filenames (auth, payments, user-service) — weaker but still useful
  const wordRe = /\b([a-z][a-z0-9_-]{2,})\b/g;
  const words = prompt.match(wordRe) || [];
  for (const w of words) {
    if (w.length >= 4 && !COMMON_WORDS.has(w)) fragments.add(w);
  }

  return fragments;
}

// Words that appear in prompts but don't narrow file scope
const COMMON_WORDS = new Set([
  'the', 'and', 'for', 'with', 'this', 'that', 'from', 'into',
  'when', 'then', 'should', 'must', 'does', 'you', 'your',
  'fix', 'add', 'new', 'update', 'create', 'delete', 'make',
  'file', 'files', 'test', 'tests', 'code', 'function', 'method',
  'agent', 'subagent', 'task', 'run', 'check', 'verify',
  'implement', 'build', 'write', 'edit', 'refactor', 'review',
]);

/**
 * A file is "in scope" if any of its path components matches any scope
 * fragment. Lenient by design — we want to flag obvious spillover, not
 * punish reasonable adjacent edits.
 */
function isInScope(filePath: string, scope: Set<string>): boolean {
  if (scope.size === 0) return true; // No scope = can't audit = trust the agent
  // Direct hit on the full path or basename
  if (scope.has(filePath)) return true;
  if (scope.has(basename(filePath))) return true;
  // Any scope fragment appears as a substring of the path
  const lower = filePath.toLowerCase();
  for (const frag of scope) {
    if (frag.length < 4) continue;
    if (lower.includes(frag.toLowerCase())) return true;
  }
  return false;
}

export function subagentScopeAuditor(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const transcriptPath = (input as unknown as { agent_transcript_path?: string }).agent_transcript_path;
  if (!transcriptPath) return outputSilentSuccess();

  const edited = extractEditedFiles(transcriptPath);
  if (edited.length === 0) return outputSilentSuccess();

  const prompt = readSpawnPrompt(transcriptPath);
  const scope = extractScopeFragments(prompt);

  if (scope.size === 0) {
    ctx.log(HOOK_NAME, `No extractable scope — skipping audit for ${edited.length} edited files`);
    return outputSilentSuccess();
  }

  const outOfScope = edited.filter(f => !isInScope(f, scope));
  if (outOfScope.length === 0) {
    ctx.log(HOOK_NAME, `All ${edited.length} edited files within scope`);
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `${outOfScope.length} out-of-scope edits flagged`);

  const shown = outOfScope.slice(0, MAX_OUT_OF_SCOPE_LINES);
  const more = outOfScope.length - shown.length;
  const list = shown.map(f => `  - ${f}`).join('\n');
  const suffix = more > 0 ? `\n  … and ${more} more` : '';

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext:
        `[subagent-scope-auditor] Agent edited ${outOfScope.length} file(s) that don't match its spawn prompt's scope:\n${list}${suffix}\n` +
        `Review whether these edits were intended. Advisory — changes are already applied.`,
    },
  };
}

// Testing exports
export {
  extractEditedFiles,
  extractScopeFragments,
  isInScope,
  readSpawnPrompt,
};
